+    #[test]
+    fn encode_decode_max_shard() {
+        let max_shard = (1usize << SHARD_ID_BITS) - 1;
+        let shard = ShardId(max_shard);
+        let local = 42_u64;
+        let encoded = encode_sharded_pane_id(shard, local);
+        let (s, l) = decode_sharded_pane_id(encoded);
+        assert_eq!(s, shard);
+        assert_eq!(l, local);
+    }
